// ── Ajustá esta URL si n8n corre en otro host/puerto ──
const BASE_URL = 'http://localhost:5678/webhook';

return { json: { base_url: BASE_URL } };

const results = $input.all();
const total     = results.length;
const fromCache = results.filter(r => r.json.from_cache === true).length;
const generated = results.filter(r => r.json.from_cache === false).length;
const errors    = results.filter(r => !r.json.success).length;

return {
  json: {
    total_programs: total,
    from_cache:     fromCache,
    generated:      generated,
    errors:         errors,
    finished_at:    new Date().toISOString()
  }
};
